const UNITS = { ms: 1, s: 1000, m: 60000, h: 3600000, d: 86400000 };

function parseDuration(str) {
  if (typeof str !== 'string' || str.length === 0) {
    throw new Error(`parseDuration: invalid input: ${str}`);
  }

  // Bare integer: treat as milliseconds
  if (/^\d+$/.test(str)) {
    return parseInt(str, 10);
  }

  // Tokenize: one or more <integer><unit> segments; ms must match before m
  const SEGMENT = /(\d+)(ms|[smhd])/g;
  let total = 0;
  let pos = 0;

  let match;
  while ((match = SEGMENT.exec(str)) !== null) {
    if (match.index !== pos) {
      throw new Error(`parseDuration: unexpected characters in "${str}"`);
    }
    total += parseInt(match[1], 10) * UNITS[match[2]];
    pos = match.index + match[0].length;
  }

  if (pos !== str.length) {
    throw new Error(`parseDuration: unparseable input: "${str}"`);
  }
  if (pos === 0) {
    throw new Error(`parseDuration: unparseable input: "${str}"`);
  }

  return total;
}

