node -e "
const { parseDuration } = require('./src/core/duration.js');
const cases = [
  ['30s',    30000],
  ['5m',     300000],
  ['1000ms', 1000],
  ['2h',     7200000],
  ['1h30m',  5400000],
  ['500ms',  500],
  ['250',    250],
  ['1d',     86400000],
  ['1h30m15s', 5415000],
];
let ok = true;
for (const [input, expected] of cases) {
  const got = parseDuration(input);
  const pass = got === expected;
  console.log((pass ? 'PASS' : 'FAIL') + ' parseDuration(' + JSON.stringify(input) + ') = ' + got + (pass ? '' : ' (expected ' + expected + ')'));
  if (!pass) ok = false;
}
// Error cases
for (const bad of ['abc', '', '1x', '30s leftover']) {
  try { parseDuration(bad); console.log('FAIL: should throw for ' + JSON.stringify(bad)); ok = false; }
  catch (e) { console.log('PASS: throws for ' + JSON.stringify(bad)); }
}
process.exit(ok ? 0 : 1);
" 2>&1
